// packages/react/src/components/toast/constants.ts
// Default gap between toasts
export const DEFAULT_GAP = 12;
// The default maximum number of visible toasts (visual only).
export const DEFAULT_MAX_VISIBLE_TOAST = 3;
// The maximum number of toasts to render in the RAC queue.
export const DEFAULT_RAC_MAX_VISIBLE_TOAST = Number.MAX_SAFE_INTEGER;
// The default scale factor for toasts.
export const DEFAULT_SCALE_FACTOR = 0.05;
// The default width of the toast.
export const DEFAULT_TOAST_WIDTH = 460;
// The default timeout for toasts in milliseconds (matches sonner's default).
export const DEFAULT_TOAST_TIMEOUT = 4000;

